ault(0) // Amount pending for hospital payout\n  doctorAmountPending   Float @default(0) // Amount pending for doctor payout\n\n  // Meta\n  remarks     String?   @db.Text // Free text\n  closedAt    DateTime?\n  handledById String?\n  handledBy   User?     @relation(fields: [handledById], references: [id])\n\n  // Relations\n  dischargeSheet DischargeSheet? @relation(\"DischargeSheetPLRecord\") // Optional link to discharge sheet\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([leadId])\n  @@index([closedAt])\n  @@index([month])\n  @@index([surgeryDate])\n  @@index([status])\n}\n\nmodel IncomingLead {\n  id         String   @id @default(cuid())\n  source     String?\n  payload    Json\n  status     String   @default(\"PENDING\") // PENDING, PROCESSED, FAILED\n  receivedAt DateTime @default(now())\n\n  @@index([status])\n  @@index([receivedAt])\n}\n\n// HRMS Models\n\nmodel Department {\n  id               String   @id @default(cuid())\n  name             String\n  description      String?\n  headId           String?\n  head             User?    @relation(\"DepartmentHead\", fields: [headId], references: [id])\n  shiftStartHour   Int      @default(10)\n  shiftStartMinute Int      @default(0)\n  grace1Minutes    Int      @default(15)\n  grace2Minutes    Int      @default(15)\n  penaltyMinutes   Int      @default(30)\n  penaltyAmount    Int      @default(200)\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  employees      Employee[]\n  teams          DepartmentTeam[]\n  supportTickets SupportTicket[]\n  notices        Notice[]\n\n  @@index([headId])\n  @@index([name])\n}\n\nmodel DepartmentTeam {\n  id           String     @id @default(cuid())\n  name         String\n  departmentId String\n  department   Department @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  teamLeadId   String?    @unique // Employee ID who is the team lead (one employee can only lead one team)\n  teamLead     Employee?  @relation(\"DepartmentTeamLead\", fields: [teamLeadId], references: [id])\n  members      Employee[] @relation(\"DepartmentTeamMembers\")\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  @@index([departmentId])\n  @@index([teamLeadId])\n}\n\nmodel Employee {\n  id                    String          @id @default(cuid())\n  userId                String          @unique\n  user                  User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  employeeCode          String          @unique\n  bdNumber              Int?            @unique\n  joinDate              DateTime?\n  salary                Float?\n  departmentId          String?\n  department            Department?     @relation(fields: [departmentId], references: [id])\n  teamId                String? // DepartmentTeam ID\n  team                  DepartmentTeam? @relation(\"DepartmentTeamMembers\", fields: [teamId], references: [id])\n  teamLeadOf            DepartmentTeam? @relation(\"DepartmentTeamLead\") // Employee is team lead of this team\n  managerId             String?\n  manager               Employee?       @relation(\"EmployeeHierarchy\", fields: [managerId], references: [id])\n  subordinates          Employee[]      @relation(\"EmployeeHierarchy\")\n  dateOfBirth           DateTime?\n  aadharNumber          String?\n  panNumber             String?\n  aadharDocUrl          String?\n  panDocUrl             String?\n  designation           String?\n  bankAccountName       String?\n  bankAccountNumber     String?\n  ifscCode              String?\n  uanNumber             String?\n  status                EmployeeStatus  @default(ACTIVE)\n  pipStartDate          DateTime?\n  pipEndDate            DateTime?\n  noticePeriodStartDate DateTime?\n  noticePeriodEndDate   DateTime?\n  finalWorkingDay       DateTime?\n  terminationReason     String?\n  fnfCompleted          Boolean         @default(false)\n  fnfCompletedAt        DateTime?\n  fnfCompletedById      String?\n  fnfCompletedBy        User?           @relation(\"FnFCompletedBy\", fields: [fnfCompletedById], references: [id])\n  createdAt             DateTime        @default(now())\n  updatedAt             DateTime        @updatedAt\n\n  attendanceLogs                          AttendanceLog[]\n  salaryStructures                        SalaryStructure[]\n  monthlyPayrolls                         MonthlyPayroll[]\n  attendanceNormalizationsAsSubject       AttendanceNormalization[] @relation(\"NormalizationSubject\")\n  attendanceNormalizationsRequested       AttendanceNormalization[] @relation(\"NormalizationRequester\")\n  attendanceNormalizationsApproved        AttendanceNormalization[] @relation(\"NormalizationApprover\")\n  attendanceNormalizationsManagerApproved AttendanceNormalization[] @relation(\"NormalizationManagerApprover\")\n  leaveRequests                           LeaveRequest[]\n  leaveRequestsTargetApprover             LeaveRequest[]            @relation(\"LeaveTargetApprover\")\n  leaveBalances                           LeaveBalance[]\n  payrollRecords                          PayrollRecord[]\n  documents                               EmployeeDocument[]\n  feedbacks                               Feedback[]\n  mdAppointments                          MDAppointment[]\n  mentalHealthRequests                    MentalHealthRequest[]\n  supportTickets                          SupportTicket[]\n  incrementRequests                       IncrementRequest[]\n  ijpApplications                         IJPApplication[]\n  mdTaskTeamMemberships                   MDTaskTeamMember[]\n  mdWatchlistMemberships                  MDWatchlistEmployee[]\n\n  @@index([userId])\n  @@index([employeeCode])\n  @@index([bdNumber])\n  @@index([departmentId])\n  @@index([teamId])\n  @@index([managerId])\n}\n\nmodel AttendanceLog {\n  id             String         @id @default(cuid())\n  employeeId     String\n  employee       Employee       @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  logDate        DateTime\n  punchDirection PunchDirection\n  temperature    Float          @default(0)\n  serialNumber   String?\n  createdAt      DateTime       @default(now())\n\n  @@unique([employeeId, logDate, punchDirection])\n  @@index([employeeId])\n  @@index([logDate])\n  @@index([punchDirection])\n}\n\nenum NormalizationType {\n  SELF\n  MANAGER\n  EMPLOYEE_REQUEST\n}\n\nenum NormalizationStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nmodel AttendanceNormalization {\n  id                  String              @id @default(cuid())\n  employeeId          String\n  employee            Employee            @relation(\"NormalizationSubject\", fields: [employeeId], references: [id], onDelete: Cascade)\n  date                DateTime\n  type                NormalizationType\n  requestedById       String\n  requestedBy         Employee            @relation(\"NormalizationRequester\", fields: [requestedById], references: [id], onDelete: Cascade)\n  approvedById        String?\n  approvedBy          Employee?           @relation(\"NormalizationApprover\", fields: [approvedById], references: [id], onDelete: SetNull)\n  managerApprovedById String?\n  managerApprovedBy   Employee?           @relation(\"NormalizationManagerApprover\", fields: [managerApprovedById], references: [id], onDelete: SetNull)\n  managerApprovedAt   DateTime?\n  status              NormalizationStatus @default(APPROVED)\n  reason              String?\n  /**\n   * For SELF type: 1, 2, or 3 hours of monthly allowance used. MANAGER/EMPLOYEE_REQUEST: null.\n   */\n  hoursUsed           Int?\n  /**\n   * FULL_DAY or HALF_DAY - set by manager when approving.\n   */\n  normalizeAs         String?\n  createdAt           DateTime            @default(now())\n  updatedAt           DateTime            @updatedAt\n\n  @@unique([employeeId, date])\n  @@index([employeeId])\n  @@index([approvedById])\n  @@index([requestedById])\n  @@index([managerApprovedById])\n}\n\nmodel LeaveTypeMaster {\n  id                  String   @id @default(cuid())\n  name                String   @unique\n  code                String?  @unique // e.g. \"CL\", \"SL\", \"EL\" for policy lookup\n  maxDays             Int // legacy/display; policy uses monthlyAccrual\n  monthlyAccrual      Float    @default(0) // accrual per month (e.g. 1, 0.5)\n  carryForward        Boolean  @default(false) // EL rolls to next year; CL/SL reset monthly\n  probationUnlockDays Float? // EL: 12 on month 7; others: null\n  isActive            Boolean  @default(true)\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n\n  leaveRequests LeaveRequest[]\n  leaveBalances LeaveBalance[]\n\n  @@index([name])\n  @@index([code])\n  @@index([isActive])\n}\n\nmodel LeaveRequest {\n  id               String             @id @default(cuid())\n  employeeId       String\n  employee         Employee           @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  leaveTypeId      String\n  leaveType        LeaveTypeMaster    @relation(fields: [leaveTypeId], references: [id])\n  startDate        DateTime\n  endDate          DateTime\n  days             Float // supports half-days (0.5)\n  reason           String?\n  isUnpaid         Boolean            @default(false)\n  status           LeaveRequestStatus @default(PENDING)\n  targetApproverId String?\n  targetApprover   Employee?          @relation(\"LeaveTargetApprover\", fields: [targetApproverId], references: [id])\n  approvedById     String?\n  approvedBy       User?              @relation(\"LeaveApprover\", fields: [approvedById], references: [id])\n  approvedAt       DateTime?\n  remarks          String?\n  createdAt        DateTime           @default(now())\n  updatedAt        DateTime           @updatedAt\n\n  @@index([employeeId])\n  @@index([status])\n  @@index([startDate])\n  @@index([leaveTypeId])\n  @@index([targetApproverId])\n}\n\nmodel LeaveBalance {\n  id          String          @id @default(cuid())\n  employeeId  String\n  employee    Employee        @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  leaveTypeId String\n  leaveType   LeaveTypeMaster @relation(fields: [leaveTypeId], references: [id])\n  allocated   Float           @default(0)\n  used        Float           @default(0)\n  remaining   Float           @default(0)\n  createdAt   DateTime        @default(now())\n  updatedAt   DateTime        @updatedAt\n\n  @@unique([employeeId, leaveTypeId])\n  @@index([employeeId])\n  @@index([leaveTypeId])\n}\n\nmodel Holiday {\n  id        String   @id @default(cuid())\n  date      DateTime @unique @db.Date\n  name      String\n  type      String // \"Compulsory\" | \"Optional\"\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([date])\n}\n\nmodel PayrollRecord {\n  id          String   @id @default(cuid())\n  employeeId  String\n  employee    Employee @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  month       Int\n  year        Int\n  disbursedAt DateTime\n  basicSalary Float\n  grossSalary Float\n  netSalary   Float\n  status      String   @default(\"PENDING\")\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  components PayrollComponent[]\n\n  @@unique([employeeId, month, year])\n  @@index([employeeId])\n  @@index([month, year])\n}\n\nmodel PayrollComponent {\n  id              String               @id @default(cuid())\n  payrollRecordId String\n  payrollRecord   PayrollRecord        @relation(fields: [payrollRecordId], references: [id], onDelete: Cascade)\n  componentType   PayrollComponentType\n  name            String\n  amount          Float\n  createdAt       DateTime             @default(now())\n  updatedAt       DateTime             @updatedAt\n\n  @@index([payrollRecordId])\n  @@index([componentType])\n}\n\nmodel SalaryStructure {\n  id                  String    @id @default(cuid())\n  employeeId          String\n  employee            Employee  @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  annualCtc           Float\n  monthlyGross        Float\n  basicSalary         Float\n  hraAllowance        Float     @default(0)\n  medicalAllowance    Float\n  conveyanceAllowance Float\n  otherAllowance      Float     @default(0)\n  specialAllowance    Float\n  insuranceDeduction  Float     @default(0)\n  applyPf             Boolean   @default(true)\n  applyTds            Boolean   @default(false)\n  tdsMonthly          Float     @default(0)\n  tdsRatePercent      Float?\n  effectiveFrom       DateTime\n  effectiveTo         DateTime?\n  createdAt           DateTime  @default(now())\n  updatedAt           DateTime  @updatedAt\n\n  @@index([employeeId])\n  @@index([effectiveFrom])\n}\n\nenum MonthlyPayrollStatus {\n  DRAFT\n  APPROVED\n  PAID\n}\n\nmodel MonthlyPayroll {\n  id                 String               @id @default(cuid())\n  employeeId         String\n  employee           Employee             @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  month              Int\n  year               Int\n  totalDaysInMonth   Int\n  payableDays        Float\n  unpaidLeaves       Int                  @default(0)\n  paidLeaves         Int                  @default(0)\n  halfDays           Int                  @default(0)\n  lateFines          Float                @default(0)\n  adjustedBasic      Float\n  adjustedHra        Float                @default(0)\n  adjustedMedical    Float\n  adjustedConveyance Float\n  adjustedOther      Float\n  adjustedSpecial    Float\n  adjustedGross      Float\n  epfEmployee        Float\n  applyEsic          Boolean              @default(false)\n  esicAmount         Float                @default(0)\n  applyTds           Boolean              @default(false)\n  tdsAmount          Float                @default(0)\n  insurance          Float                @default(0)\n  totalDeductions    Float\n  epfEmployer        Float\n  netPayable         Float\n  status             MonthlyPayrollStatus @default(DRAFT)\n  disbursedAt        DateTime?\n  approvedById       String?\n  paidAt             DateTime?\n  generatedAt        DateTime             @default(now())\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime             @updatedAt\n\n  @@unique([employeeId, month, year])\n  @@index([employeeId])\n  @@index([month, year])\n  @@index([status])\n}\n\n// Employee Documents (Offer Letter, Appraisal, etc.)\nmodel EmployeeDocument {\n  id             String       @id @default(cuid())\n  employeeId     String\n  employee       Employee     @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  documentType   DocumentType\n  documentUrl    String?\n  title          String?\n  metadata       Json?\n  generatedAt    DateTime     @default(now())\n  createdAt      DateTime     @default(now())\n  updatedAt      DateTime     @updatedAt\n  ackToken       String?      @unique\n  acknowledgedAt DateTime?\n  acknowledgedIp String?\n\n  @@index([employeeId])\n  @@index([documentType])\n}\n\n// Feedback 360 - Employee submits, HR reviews\nmodel Feedback {\n  id         String         @id @default(cuid())\n  employeeId String\n  employee   Employee       @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  content    String\n  status     FeedbackStatus @default(PENDING)\n  createdAt  DateTime       @default(now())\n  updatedAt  DateTime       @updatedAt\n\n  @@index([employeeId])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// Anonymous Messages to MD - No user info stored\nmodel AnonymousMessage {\n  id        String   @id @default(cuid())\n  message   String\n  isRead    Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  @@index([isRead])\n  @@index([createdAt])\n}\n\n// MD Appointment Requests\nmodel MDAppointment {\n  id            String            @id @default(cuid())\n  employeeId    String\n  employee      Employee          @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  preferredDate DateTime?\n  reason        String\n  status        AppointmentStatus @default(PENDING)\n  remarks       String?\n  createdAt     DateTime          @default(now())\n  updatedAt     DateTime          @updatedAt\n\n  @@index([employeeId])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// Mental Health Support Requests (48hr SLA)\nmodel MentalHealthRequest {\n  id          String        @id @default(cuid())\n  employeeId  String\n  employee    Employee      @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  reason      String?\n  status      RequestStatus @default(PENDING)\n  hrResponse  String?\n  respondedAt DateTime?\n  createdAt   DateTime      @default(now())\n  updatedAt   DateTime      @updatedAt\n\n  @@index([employeeId])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// Help Support Tickets (48hr SLA)\nmodel SupportTicket {\n  id             String         @id @default(cuid())\n  employeeId     String\n  employee       Employee       @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  departmentId   String?\n  department     Department?    @relation(fields: [departmentId], references: [id])\n  targetHeadRole String? // UserRole value e.g. HR_HEAD, FINANCE_HEAD\n  subject        String\n  description    String\n  priority       TicketPriority @default(MEDIUM)\n  status         TicketStatus   @default(OPEN)\n  response       String?\n  respondedAt    DateTime?\n  createdAt      DateTime       @default(now())\n  updatedAt      DateTime       @updatedAt\n\n  @@index([employeeId])\n  @@index([departmentId])\n  @@index([targetHeadRole])\n  @@index([status])\n  @@index([priority])\n  @@index([createdAt])\n}\n\n// Increment Requests\nmodel IncrementRequest {\n  id                 String        @id @default(cuid())\n  employeeId         String\n  employee           Employee      @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  currentSalary      Float\n  requestedAmount    Float?\n  reason             String\n  achievements       String?\n  documents          Json?\n  status             RequestStatus @default(PENDING)\n  approvalPercentage Float?\n  hrRemarks          String?\n  createdAt          DateTime      @default(now())\n  updatedAt          DateTime      @updatedAt\n\n  @@index([employeeId])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// Internal Job Postings\nmodel InternalJobPosting {\n  id           String   @id @default(cuid())\n  title        String\n  description  String\n  department   String?\n  requirements String?\n  isActive     Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  applications IJPApplication[]\n\n  @@index([isActive])\n  @@index([createdAt])\n}\n\n// IJP Applications / Referrals\nmodel IJPApplication {\n  id             String             @id @default(cuid())\n  postingId      String\n  posting        InternalJobPosting @relation(fields: [postingId], references: [id], onDelete: Cascade)\n  referredById   String\n  referrer       Employee           @relation(fields: [referredById], references: [id], onDelete: Cascade)\n  candidateName  String\n  candidateEmail String?\n  candidatePhone String?\n  resumeUrl      String\n  description    String?\n  documents      Json?\n  status         ApplicationStatus  @default(PENDING)\n  createdAt      DateTime           @default(now())\n  updatedAt      DateTime           @updatedAt\n\n  @@index([postingId])\n  @@index([referredById])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// ==========================================\n// Finance Ledger Module\n// ==========================================\n\nenum PartyType {\n  BUYER\n  SELLER\n  VENDOR\n  CLIENT\n  SUPPLIER\n  OTHER\n}\n\nenum TransactionType {\n  CREDIT\n  DEBIT\n  SELF_TRANSFER\n}\n\nenum LedgerStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum FinancePaymentType {\n  EXPENSE\n  NON_EXPENSE\n  RECEIPT\n}\n\nenum LedgerAuditAction {\n  CREATED\n  UPDATED\n  APPROVED\n  REJECTED\n  DELETED\n  EDIT_REQUESTED\n  EDIT_APPROVED\n  EDIT_REJECTED\n}\n\n// Party Master - Centralized list of all parties\nmodel PartyMaster {\n  id           String    @id @default(cuid())\n  name         String\n  partyType    PartyType\n  contactName  String?\n  contactEmail String?\n  contactPhone String?\n  gstNumber    String?\n  panNumber    String?\n  address      String?\n  isActive     Boolean   @default(true)\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  ledgerEntries LedgerEntry[]\n  itemsSupplied ItemMaster[]\n  purchases     PurchaseTransaction[]\n\n  @@index([name])\n  @@index([partyType])\n  @@index([isActive])\n}\n\n// Head Master - Categories for transactions\nmodel HeadMaster {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  department  String?\n  description String?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  ledgerEntries LedgerEntry[]\n\n  @@index([name])\n  @@index([isActive])\n}\n\n// Project Master - For sales/revenue categorization\nmodel ProjectMaster {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  description String?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  salesEntries SalesEntry[]\n\n  @@index([name])\n  @@index([isActive])\n}\n\n// Payment Type Master - Expense classification\nmodel PaymentTypeMaster {\n  id          String             @id @default(cuid())\n  name        String             @unique\n  paymentType FinancePaymentType\n  description String?\n  isActive    Boolean            @default(true)\n  createdAt   DateTime           @default(now())\n  updatedAt   DateTime           @updatedAt\n\n  ledgerEntries LedgerEntry[]\n\n  @@index([paymentType])\n  @@index([isActive])\n}\n\n// Payment Mode Master - Bank accounts/cash with balances\nmodel PaymentModeMaster {\n  id             String   @id @default(cuid())\n  name           String   @unique\n  description    String?\n  openingBalance Float    @default(0)\n  currentBalance Float    @default(0)\n  isActive       Boolean  @default(true)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  ledgerEntries LedgerEntry[]\n  fromTransfers LedgerEntry[] @relation(\"FromPaymentMode\")\n  toTransfers   LedgerEntry[] @relation(\"ToPaymentMode\")\n\n  @@index([name])\n  @@index([isActive])\n}\n\n// Ledger Entry - Core transaction record\nmodel LedgerEntry {\n  id                 String             @id @default(cuid())\n  serialNumber       String             @unique\n  transactionType    TransactionType\n  transactionDate    DateTime           @default(now())\n  partyId            String?\n  party              PartyMaster?       @relation(fields: [partyId], references: [id])\n  description        String\n  headId             String?\n  head               HeadMaster?        @relation(fields: [headId], references: [id])\n  paymentTypeId      String?\n  paymentType        PaymentTypeMaster? @relation(fields: [paymentTypeId], references: [id])\n  paymentAmount      Float? // For DEBIT entries (Total = componentA + componentB)\n  componentA         Float? // For DEBIT entries - Main expense (more relevant)\n  componentB         Float? // For DEBIT entries - Claimable amount (18%, 5%, 0%, etc.)\n  receivedAmount     Float? // For CREDIT entries\n  paymentModeId      String? // For CREDIT/DEBIT entries (or \"from\" for SELF_TRANSFER)\n  paymentMode        PaymentModeMaster? @relation(fields: [paymentModeId], references: [id])\n  // Self transfer fields\n  fromPaymentModeId  String? // Source payment mode for SELF_TRANSFER\n  fromPaymentMode    PaymentModeMaster? @relation(\"FromPaymentMode\", fields: [fromPaymentModeId], references: [id])\n  toPaymentModeId    String? // Destination payment mode for SELF_TRANSFER\n  toPaymentMode      PaymentModeMaster? @relation(\"ToPaymentMode\", fields: [toPaymentModeId], references: [id])\n  transferAmount     Float? // Transfer amount for SELF_TRANSFER\n  openingBalance     Float // Snapshot at time of transaction\n  currentBalance     Float // Balance after transaction (calculated)\n  status             LedgerStatus       @default(PENDING)\n  rejectionReason    String?\n  // Soft delete fields\n  isDeleted          Boolean            @default(false)\n  deletedAt          DateTime?\n  deletedById        String?\n  deletedBy          User?              @relation(\"LedgerDeleter\", fields: [deletedById], references: [id])\n  deletedReason      String?\n  // Edit request fields\n  editRequestStatus  LedgerStatus? // PENDING, APPROVED, or REJECTED for edit requests\n  editRequestReason  String? // Why edit is needed (required when requesting)\n  editRequestData    Json? // Requested changes\n  editRequestedById  String?\n  editRequestedBy    User?              @relation(\"LedgerEditRequester\", fields: [editRequestedById], references: [id])\n  editRequestedAt    DateTime?\n  editApprovalReason String? // Why approval was given/rejected (required when approving/rejecting)\n  editApprovedById   String?\n  editApprovedBy     User?              @relation(\"LedgerEditApprover\", fields: [editApprovedById], references: [id])\n  editApprovedAt     DateTime?\n  editCount          Int                @default(0) // Number of completed edit cycles (max 5)\n  attachments        Json? // Array of {name, url, type}\n  createdById        String\n  createdBy          User               @relation(\"LedgerCreator\", fields: [createdById], references: [id])\n  approvedById       String?\n  approvedBy         User?              @relation(\"LedgerApprover\", fields: [approvedById], references: [id])\n  approvedAt         DateTime?\n  createdAt          DateTime           @default(now())\n  updatedAt          DateTime           @updatedAt\n\n  auditLogs LedgerAuditLog[]\n\n  @@index([serialNumber])\n  @@index([transactionType])\n  @@index([transactionDate])\n  @@index([partyId])\n  @@index([headId])\n  @@index([paymentModeId])\n  @@index([fromPaymentModeId])\n  @@index([toPaymentModeId])\n  @@index([status])\n  @@index([createdById])\n  @@index([isDeleted])\n  @@index([editRequestStatus])\n}\n\n// Ledger Audit Log - Tracks all changes and approvals\nmodel LedgerAuditLog {\n  id            String            @id @default(cuid())\n  ledgerEntryId String\n  ledgerEntry   LedgerEntry       @relation(fields: [ledgerEntryId], references: [id], onDelete: Cascade)\n  action        LedgerAuditAction\n  previousData  Json?\n  newData       Json?\n  reason        String?\n  performedById String\n  performedBy   User              @relation(\"LedgerAuditPerformer\", fields: [performedById], references: [id])\n  performedAt   DateTime          @default(now())\n\n  @@index([ledgerEntryId])\n  @@index([action])\n  @@index([performedAt])\n}\n\n// Sales Entry - Booked sales/revenue (does not affect bank balances)\nmodel SalesEntry {\n  id              String        @id @default(cuid())\n  serialNumber    String        @unique // Format: SL-0001\n  transactionDate DateTime      @default(now())\n  projectId       String\n  project         ProjectMaster @relation(fields: [projectId], references: [id])\n  description     String\n  amount          Float // Booked sale amount\n  notes           String?\n  isDeleted       Boolean       @default(false)\n  deletedAt       DateTime?\n  createdById     String\n  createdBy       User          @relation(\"SalesCreator\", fields: [createdById], references: [id])\n  createdAt       DateTime      @default(now())\n  updatedAt       DateTime      @updatedAt\n\n  @@index([transactionDate])\n  @@index([projectId])\n  @@index([isDeleted])\n}\n\n// ==========================================\n// Inventory Management Module\n// ==========================================\n\nenum LocationType {\n  WAREHOUSE\n  SUB_WAREHOUSE\n}\n\nenum StockMovementType {\n  PURCHASE\n  ISSUE\n  ADJUSTMENT\n}\n\nenum InventoryTransactionStatus {\n  PENDING\n  COMPLETED\n  CANCELLED\n}\n\n// Location Master - Hierarchical warehouse structure\nmodel LocationMaster {\n  id          String           @id @default(cuid())\n  name        String\n  code        String           @unique\n  type        LocationType\n  parentId    String?\n  parent      LocationMaster?  @relation(\"LocationHierarchy\", fields: [parentId], references: [id])\n  children    LocationMaster[] @relation(\"LocationHierarchy\")\n  description String?\n  isActive    Boolean          @default(true)\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  items          ItemMaster[]\n  purchases      PurchaseTransaction[]\n  issues         IssueTransaction[]\n  stockMovements StockMovement[]\n\n  @@index([code])\n  @@index([type])\n  @@index([parentId])\n  @@index([isActive])\n}\n\n// Item Master - Inventory items\nmodel ItemMaster {\n  id                String         @id @default(cuid())\n  itemCode          String         @unique\n  name              String\n  price             Float\n  unit              String\n  supplierId        String\n  supplier          PartyMaster    @relation(fields: [supplierId], references: [id])\n  locationId        String\n  location          LocationMaster @relation(fields: [locationId], references: [id])\n  minimumStockLevel Float\n  maximumStockLevel Float\n  description       String?\n  isActive          Boolean        @default(true)\n  createdAt         DateTime       @default(now())\n  updatedAt         DateTime       @updatedAt\n\n  purchases      PurchaseTransaction[]\n  issues         IssueTransaction[]\n  stockMovements StockMovement[]\n\n  @@index([itemCode])\n  @@index([name])\n  @@index([supplierId])\n  @@index([locationId])\n  @@index([isActive])\n}\n\n// Stock Movement - Track stock changes per item per location\nmodel StockMovement {\n  id            String            @id @default(cuid())\n  itemId        String\n  item          ItemMaster        @relation(fields: [itemId], references: [id])\n  locationId    String\n  location      LocationMaster    @relation(fields: [locationId], references: [id])\n  quantity      Float\n  movementType  StockMovementType\n  referenceId   String\n  referenceType StockMovementType\n  createdAt     DateTime          @default(now())\n  createdById   String\n  createdBy     User              @relation(\"StockMovementCreator\", fields: [createdById], references: [id])\n\n  @@index([itemId])\n  @@index([locationId])\n  @@index([referenceId])\n  @@index([createdAt])\n}\n\n// Purchase Transaction - Item purchases\nmodel PurchaseTransaction {\n  id             String                     @id @default(cuid())\n  purchaseNumber String                     @unique\n  itemId         String\n  item           ItemMaster                 @relation(fields: [itemId], references: [id])\n  supplierId     String\n  supplier       PartyMaster                @relation(fields: [supplierId], references: [id])\n  locationId     String\n  location       LocationMaster             @relation(fields: [locationId], references: [id])\n  quantity       Float\n  unitPrice      Float\n  totalPrice     Float\n  purchaseDate   DateTime                   @default(now())\n  description    String?\n  status         InventoryTransactionStatus @default(PENDING)\n  createdAt      DateTime                   @default(now())\n  createdById    String\n  createdBy      User                       @relation(\"PurchaseCreator\", fields: [createdById], references: [id])\n  updatedAt      DateTime                   @updatedAt\n\n  @@index([purchaseNumber])\n  @@index([itemId])\n  @@index([supplierId])\n  @@index([locationId])\n  @@index([purchaseDate])\n  @@index([status])\n}\n\n// Issue Transaction - Item issues to employees\nmodel IssueTransaction {\n  id          String                     @id @default(cuid())\n  issueNumber String                     @unique\n  itemId      String\n  item        ItemMaster                 @relation(fields: [itemId], references: [id])\n  locationId  String\n  location    LocationMaster             @relation(fields: [locationId], references: [id])\n  quantity    Float\n  unitPrice   Float\n  totalPrice  Float\n  issuedToId  String\n  issuedTo    User                       @relation(\"IssueRecipient\", fields: [issuedToId], references: [id])\n  issueDate   DateTime                   @default(now())\n  description String?\n  status      InventoryTransactionStatus @default(PENDING)\n  createdAt   DateTime                   @default(now())\n  createdById String\n  createdBy   User                       @relation(\"IssueCreator\", fields: [createdById], references: [id])\n  updatedAt   DateTime                   @updatedAt\n\n  @@index([issueNumber])\n  @@index([itemId])\n  @@index([locationId])\n  @@index([issuedToId])\n  @@index([issueDate])\n  @@index([status])\n}\n\n// Lead Remark - Stores remarks from MySQL lead_remarks table\nmodel LeadRemark {\n  id         String   @id @default(cuid())\n  leadRef    String // MySQL lead.id as string reference\n  remarks    String   @db.Text\n  updateBy   Int? // MySQL user ID reference\n  updateDate DateTime\n  ip         String?\n  leadStatus Int? // MySQL status ID\n  createdAt  DateTime @default(now())\n\n  @@index([leadRef])\n  @@index([updateDate])\n}\n\n// Sync State - Tracks MySQL sync progress\nmodel SyncState {\n  id             String   @id @default(cuid())\n  sourceType     String   @unique @default(\"mysql_leads\") // For future extensibility\n  lastSyncedDate DateTime\n  lastSyncedId   Int? // Last MySQL lead.id processed\n  recordsCount   Int      @default(0)\n  lastRunAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n}\n\n// ==========================================\n// KYP (Know Your Patient) Module\n// ==========================================\n\nmodel KYPSubmission {\n  id     String @id @default(cuid())\n  leadId String @unique\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  // Form fields (all optional)\n  aadhar        String?\n  pan           String?\n  insuranceCard String?\n  disease       String?\n  location      String? // City name\n  area          String? // Area within city (Call 1 - Basic)\n  remark        String?\n  insuranceType InsuranceType?\n\n  // File URLs (stored in S3)\n  aadharFileUrl        String?\n  panFileUrl           String?\n  insuranceCardFileUrl String?\n  prescriptionFileUrl  String?\n  diseasePhotos        Json? // Array of {name, url}\n  otherFiles           Json? // Array of {name, url} objects\n\n  // Call 2 - Detailed: patient consent\n  patientConsent Boolean @default(false)\n\n  // Status tracking\n  status        KYPStatus @default(PENDING)\n  submittedById String\n  submittedBy   User      @relation(\"KYPSubmitter\", fields: [submittedById], references: [id])\n  submittedAt   DateTime  @default(now())\n\n  // Pre-authorization (filled by Insurance)\n  preAuthData PreAuthorization?\n\n  // Discharge sheet (optional link)\n  dischargeSheet DischargeSheet? @relation(\"DischargeSheetKYP\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([leadId])\n  @@index([status])\n  @@index([submittedAt])\n}\n\nmodel PreAuthorization {\n  id              String        @id @default(cuid())\n  kypSubmissionId String        @unique\n  kypSubmission   KYPSubmission @relation(fields: [kypSubmissionId], references: [id], onDelete: Cascade)\n\n  // All fields as strings (per requirement)\n  sumInsured             String?\n  balanceInsured         String?\n  roomRent               String?\n  capping                String?\n  copay                  String?\n  icu                    String?\n  hospitalNameSuggestion String?\n  insurance              String?\n  tpa                    String?\n\n  // Insurance: multiple hospitals and room types (JSON)\n  hospitalSuggestions Json? // string[] — multiple suggested hospitals\n  roomTypes           Json? // { name: string, rent: string }[] — multiple room types with rent limits\n\n  // BD Pre-Auth Request fields (selection from Insurance suggestions)\n  requestedHospitalName String?\n  requestedRoomType     String?\n  bdSuggestedHospital   String?   @db.Text\n  diseaseDescription    String?   @db.Text\n  diseaseImages         Json? // Array of {name, url}\n  preAuthRaisedAt       DateTime?\n  preAuthRaisedById     String?\n  preAuthRaisedBy       User?     @relation(\"PreAuthRaiser\", fields: [preAuthRaisedById], references: [id])\n\n  // New hospital request flow (BD requested a hospital not in suggestions)\n  isNewHospitalRequest     Boolean @default(false)\n  newHospitalPreAuthRaised Boolean @default(false) // Insurance marks they raised pre-auth for new hospital\n\n  // Expected dates (persisted)\n  expectedAdmissionDate DateTime?\n  expectedSurgeryDate   DateTime?\n\n  // Investigation files\n  investigationFileUrls Json? // Array of {name, url}\n\n  // Prescription files (uploaded by BD during pre-auth raise)\n  prescriptionFiles Json? // Array of {name, url}\n\n  // BD notes for Insurance team\n  notes String? @db.Text\n\n  // Insurance type (auto-filled from KYPSubmission)\n  insuranceType String?\n\n  handledById String?\n  handledBy   User?     @relation(\"PreAuthHandler\", fields: [handledById], references: [id])\n  handledAt   DateTime?\n\n  // Approval/Rejection\n  approvalStatus     PreAuthStatus @default(PENDING)\n  approvedAmount     Float?\n  approvalNotes      String?       @db.Text\n  rejectionReason    String?       @db.Text\n  rejectionLetterUrl String?\n  approvedAt         DateTime?\n  rejectedAt         DateTime?\n\n  // Q&A Queries (kept for backward compat; chat is primary)\n  queries InsuranceQuery[]\n\n  // Hospital suggestions (replaces flat JSON; use suggestedHospitals relation)\n  suggestedHospitals HospitalSuggestion[]\n\n  // PDF generation\n  pdfVersions PreAuthPDF[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([kypSubmissionId])\n  @@index([preAuthRaisedById])\n}\n\n// ==========================================\n// Hospital Suggestion (Insurance suggests hospitals with tentative bills/room rents)\n// ==========================================\n\nmodel HospitalSuggestion {\n  id                  String           @id @default(cuid())\n  preAuthId           String\n  preAuth             PreAuthorization @relation(fields: [preAuthId], references: [id], onDelete: Cascade)\n  hospitalName        String\n  suggestedDoctor     String?\n  tentativeBill       Float?\n  roomRentGeneral     Float?\n  roomRentSingle      Float?\n  roomRentDeluxe      Float?\n  roomRentSemiPrivate Float?\n  notes               String?          @db.Text\n  createdAt           DateTime         @default(now())\n\n  @@index([preAuthId])\n}\n\nmodel Notification {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  type      NotificationType\n  title     String\n  message   String\n  link      String? // URL to relevant page\n  relatedId String? // ID of related entity (leadId, kypSubmissionId, etc)\n\n  isRead    Boolean   @default(false)\n  readAt    DateTime?\n  createdAt DateTime  @default(now())\n\n  @@index([userId])\n  @@index([isRead])\n  @@index([createdAt])\n}\n\n// ==========================================\n// Notice Board\n// ==========================================\n\nmodel Notice {\n  id                 String           @id @default(cuid())\n  title              String\n  body               String           @db.Text\n  createdById        String\n  createdBy          User             @relation(\"NoticeCreator\", fields: [createdById], references: [id], onDelete: Cascade)\n  targetType         NoticeTargetType\n  targetDepartmentId String?\n  targetDepartment   Department?      @relation(fields: [targetDepartmentId], references: [id])\n  createdAt          DateTime         @default(now())\n\n  recipients NoticeRecipient[]\n\n  @@index([createdById])\n  @@index([createdAt])\n}\n\nmodel NoticeRecipient {\n  id             String    @id @default(cuid())\n  noticeId       String\n  notice         Notice    @relation(fields: [noticeId], references: [id], onDelete: Cascade)\n  userId         String\n  user           User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  acknowledgedAt DateTime?\n  createdAt      DateTime  @default(now())\n\n  @@unique([noticeId, userId])\n  @@index([noticeId])\n  @@index([userId])\n  @@index([acknowledgedAt])\n}\n\n// ==========================================\n// MD Approval Requests\n// ==========================================\n\nmodel MDApprovalRequest {\n  id                      String           @id @default(cuid())\n  title                   String\n  description             String?          @db.Text\n  amount                  Float?\n  attachments             Json?\n  status                  MDApprovalStatus @default(PENDING)\n  requestedById           String\n  requestedBy             User             @relation(\"MDApprovalRequester\", fields: [requestedById], references: [id], onDelete: Cascade)\n  respondedById           String?\n  respondedBy             User?            @relation(\"MDApprovalResponder\", fields: [respondedById], references: [id])\n  responseNote            String?          @db.Text\n  respondedAt             DateTime?\n  financeAcknowledged     Boolean          @default(false)\n  financeAcknowledgedById String?\n  financeAcknowledgedBy   User?            @relation(\"MDApprovalFinanceAck\", fields: [financeAcknowledgedById], references: [id])\n  financeAcknowledgedAt   DateTime?\n  createdAt               DateTime         @default(now())\n  updatedAt               DateTime         @updatedAt\n\n  @@index([requestedById])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// ==========================================\n// User Feature Permissions (IT Permissions)\n// ==========================================\n\nmodel UserFeaturePermission {\n  id          String   @id @default(cuid())\n  userId      String\n  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  featureKey  String\n  enabled     Boolean  @default(false)\n  grantedById String?\n  grantedBy   User?    @relation(\"PermissionGranter\", fields: [grantedById], references: [id])\n  updatedAt   DateTime @updatedAt\n\n  @@unique([userId, featureKey])\n  @@index([userId])\n  @@index([featureKey])\n}\n\n// ==========================================\n// Insurance Query (Q&A Flow)\n// ==========================================\n\nmodel InsuranceQuery {\n  id                 String           @id @default(cuid())\n  preAuthorizationId String\n  preAuthorization   PreAuthorization @relation(fields: [preAuthorizationId], references: [id], onDelete: Cascade)\n\n  question String      @db.Text // Question from Insurance\n  answer   String?     @db.Text // Answer from BD\n  status   QueryStatus @default(PENDING)\n\n  raisedById   String // Insurance user who raised the query\n  raisedBy     User    @relation(\"QueryRaiser\", fields: [raisedById], references: [id])\n  answeredById String? // BD user who answered\n  answeredBy   User?   @relation(\"QueryAnswerer\", fields: [answeredById], references: [id])\n\n  raisedAt   DateTime  @default(now())\n  answeredAt DateTime?\n  resolvedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([preAuthorizationId])\n  @@index([status])\n  @@index([raisedAt])\n}\n\n// ==========================================\n// Pre-Auth PDF\n// ==========================================\n\nmodel PreAuthPDF {\n  id                 String           @id @default(cuid())\n  preAuthorizationId String\n  preAuthorization   PreAuthorization @relation(fields: [preAuthorizationId], references: [id], onDelete: Cascade)\n\n  version     Int\n  pdfUrl      String\n  recipients  Json? // Array of recipients\n  sentAt      DateTime?\n  createdById String\n  createdBy   User      @relation(\"PDFCreator\", fields: [createdById], references: [id])\n  createdAt   DateTime  @default(now())\n\n  @@index([preAuthorizationId])\n}\n\n// ==========================================\n// Admission Record\n// ==========================================\n\nmodel AdmissionRecord {\n  id     String @id @default(cuid())\n  leadId String @unique\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  admissionDate       DateTime\n  admissionTime       String\n  admittingHospital   String\n  expectedSurgeryDate DateTime?\n\n  surgeryDate        DateTime?\n  surgeryTime        String?\n  hospitalAddress    String?\n  googleMapLocation  String?\n  tpa                String?\n  instrument         String?\n  implantConsumables String?\n  noMediendLogo      Boolean   @default(false)\n\n  // Cab Service - Admission Pickup\n  cabAdmissionPickupLocation String?\n  cabAdmissionPickupDateTime DateTime?\n  cabAdmissionFrom           String?\n  cabAdmissionTo             String?\n\n  // Cab Service - Discharge Pickup\n  cabDischargePickupLocation String?\n  cabDischargePickupDateTime DateTime?\n  cabDischargeFrom           String?\n  cabDischargeTo             String?\n\n  // IPD Status tracking\n  ipdStatus          IpdStatus?\n  ipdStatusReason    String?\n  newSurgeryDate     DateTime?\n  ipdDischargeDate   DateTime?\n  ipdStatusNotes     String?    @db.Text\n  ipdStatusUpdatedAt DateTime?\n\n  notes String? @db.Text\n\n  initiatedById String\n  initiatedBy   User     @relation(\"AdmissionInitiator\", fields: [initiatedById], references: [id])\n  initiatedAt   DateTime @default(now())\n\n  @@index([leadId])\n}\n\n// ==========================================\n// Insurance Initiate Form (Pre-discharge form filled by Insurance)\n// ==========================================\n\nmodel InsuranceInitiateForm {\n  id     String @id @default(cuid())\n  leadId String @unique\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  // Financial fields\n  totalBillAmount           Float   @default(0)\n  discount                  Float   @default(0)\n  otherReductions           Float   @default(0)\n  copay                     Float? // Autofilled from pre-auth\n  copayBuffer               Float   @default(0)\n  deductible                Float   @default(0)\n  exceedsPolicyLimit        String? // String field\n  policyDeductibleAmount    Float   @default(0)\n  totalAuthorizedAmount     Float   @default(0)\n  amountToBePaidByInsurance Float   @default(0)\n  roomCategory              String? // From pre-auth requestedRoomType\n\n  // File upload\n  initialApprovalByHospitalUrl String? // Optional file upload for initial approval by hospital\n\n  // Relations\n  createdById String\n  createdBy   User     @relation(\"InsuranceInitiateFormCreator\", fields: [createdById], references: [id])\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([leadId])\n}\n\n// ==========================================\n// Case Stage History\n// ==========================================\n\nmodel CaseStageHistory {\n  id     String @id @default(cuid())\n  leadId String\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  fromStage   CaseStage?\n  toStage     CaseStage\n  changedById String\n  changedBy   User       @relation(\"CaseStageChanger\", fields: [changedById], references: [id])\n  changedAt   DateTime   @default(now())\n  note        String?    @db.Text\n\n  @@index([leadId])\n  @@index([changedAt])\n}\n\n// ==========================================\n// Case Chat (BD <-> Insurance 2-way chat on patient page)\n// ==========================================\n\nmodel CaseChatMessage {\n  id        String          @id @default(cuid())\n  leadId    String\n  lead      Lead            @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  senderId  String? // null for system messages\n  sender    User?           @relation(\"CaseChatSender\", fields: [senderId], references: [id])\n  type      ChatMessageType // TEXT, FILE, SYSTEM\n  content   String          @db.Text\n  fileUrl   String?\n  fileName  String?\n  createdAt DateTime        @default(now())\n\n  @@index([leadId, createdAt])\n}\n\n// ==========================================\n// Discharge Sheet\n// ==========================================\n\nmodel DischargeSheet {\n  id              String         @id @default(cuid())\n  leadId          String         @unique\n  lead            Lead           @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  kypSubmissionId String?        @unique // Optional link to KYP\n  kypSubmission   KYPSubmission? @relation(\"DischargeSheetKYP\", fields: [kypSubmissionId], references: [id])\n\n  // Core Identification\n  month              DateTime? // Reporting month\n  dischargeDate      DateTime? // Date of discharge\n  surgeryDate        DateTime? // Date of surgery\n  status             String? // Case status\n  paymentType        String? // Payment mode\n  approvedOrCash     String? // Approved / Cash\n  paymentCollectedAt String? // Collection source\n\n  // People & Ownership\n  managerRole  String? // ATL / TL / ACM / CM / SCM\n  managerName  String? // Person name\n  bdmName      String? // Business Development Manager\n  patientName  String? // Patient full name\n  patientPhone String? // Phone number\n  doctorName   String? // Treating doctor\n  hospitalName String? // Hospital\n\n  // Case Details\n  category   String? // Cosmetic / Medical\n  treatment  String? // Procedure\n  circle     String? // City / region\n  leadSource String? // Source of lead\n\n  // A. Patient & Policy (additions)\n  tentativeAmount Float?\n  copayPct        Float?\n\n  // B. Documents (upload URLs)\n  dischargeSummaryUrl String?\n  otNotesUrl          String? // OT notes upload\n  codesCount          Int?\n  finalBillUrl        String?\n  settlementLetterUrl String?\n\n  // C. Bill Breakup\n  roomRentAmount      Float  @default(0)\n  pharmacyAmount      Float  @default(0)\n  investigationAmount Float  @default(0)\n  consumablesAmount   Float  @default(0)\n  implantsAmount      Float  @default(0)\n  instrumentsAmount   Float?\n  totalFinalBill      Float  @default(0)\n\n  // D. Approval & Deductions\n  finalApprovedAmount Float  @default(0)\n  finalAmount         Float?\n  deductionAmount     Float  @default(0)\n  discountAmount      Float  @default(0)\n  waivedOffAmount     Float  @default(0)\n  settlementPart      Float  @default(0)\n  tdsAmount           Float  @default(0)\n  otherDeduction      Float  @default(0)\n  netSettlementAmount Float  @default(0)\n\n  // Financials (Raw) — legacy\n  totalAmount       Float @default(0) // Total case value\n  billAmount        Float @default(0) // Hospital bill\n  cashPaidByPatient Float @default(0) // Direct patient cash\n  cashOrDedPaid     Float @default(0) // Cash / deduction\n  referralAmount    Float @default(0) // Referral payout\n  cabCharges        Float @default(0) // Logistics cost\n  implantCost       Float @default(0) // Implant\n  dcCharges         Float @default(0) // D&C\n  doctorCharges     Float @default(0) // Doctor fee\n\n  // Revenue Split\n  hospitalSharePct    Float? // % (DECIMAL(5,2))\n  hospitalShareAmount Float  @default(0) // Amount\n  mediendSharePct     Float? // % (DECIMAL(5,2))\n  mediendShareAmount  Float  @default(0) // Gross share\n  mediendNetProfit    Float  @default(0) // Final profit\n\n  // Meta\n  remarks String? @db.Text // Free text\n\n  // Relations\n  createdById String // Insurance user who created\n  createdBy   User      @relation(\"DischargeSheetCreator\", fields: [createdById], references: [id])\n  plRecordId  String?   @unique // Optional link to PNL record\n  plRecord    PLRecord? @relation(\"DischargeSheetPLRecord\", fields: [plRecordId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([leadId])\n  @@index([kypSubmissionId])\n  @@index([month])\n  @@index([surgeryDate])\n  @@index([status])\n}\n\n// ==========================================\n// Outstanding Cases\n// ==========================================\n\nmodel OutstandingCase {\n  id     String @id @default(cuid())\n  leadId String @unique\n  lead   Lead   @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  // Core Identification\n  srNo            Int? // Excel serial\n  month           DateTime? // Reporting month\n  dos             DateTime? // Date of service\n  status          String? // Case status\n  paymentReceived Boolean   @default(false) // YES / NO\n\n  // People & Case\n  managerName  String? // Manager\n  bdmName      String? // BDM\n  patientName  String? // Patient\n  treatment    String? // Procedure\n  hospitalName String? // Hospital\n\n  // Financials\n  billAmount        Float @default(0) // Total bill\n  settlementAmount  Float @default(0) // Settled amount\n  cashPaidByPatient Float @default(0) // Patient cash\n  overallAmount     Float @default(0) // Total\n  implantCost       Float @default(0) // Implant\n  dciCost           Float @default(0) // DCI\n\n  // Revenue Split\n  hospitalSharePct    Float? // % (DECIMAL(5,2))\n  hospitalShareAmount Float  @default(0) // Amount\n  mediendSharePct     Float? // % (DECIMAL(5,2))\n  mediendShareAmount  Float  @default(0) // Amount\n\n  // Outstanding Tracking\n  outstandingDays Int? // Days pending (calculated)\n  remarks         String? @db.Text // Internal notes\n  remark2         String? @db.Text // Follow-ups\n\n  // Relations\n  handledById String?\n  handledBy   User?   @relation(\"OutstandingHandler\", fields: [handledById], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([leadId])\n  @@index([month])\n  @@index([dos])\n  @@index([status])\n  @@index([paymentReceived])\n}\n\n// ==========================================\n// Task Management Module\n// ==========================================\n\nmodel Task {\n  id          String       @id @default(cuid())\n  title       String\n  description String?      @db.Text\n  dueDate     DateTime?\n  priority    TaskPriority @default(MEDIUM)\n  status      TaskStatus   @default(PENDING)\n\n  // Ownership\n  assigneeId  String\n  assignee    User   @relation(\"TaskAssignee\", fields: [assigneeId], references: [id], onDelete: Cascade)\n  createdById String\n  createdBy   User   @relation(\"TaskCreator\", fields: [createdById], references: [id], onDelete: Cascade)\n\n  // Completion (set when manager approves from EMPLOYEE_DONE)\n  completedById      String?\n  completedBy        User?     @relation(\"TaskCompletedBy\", fields: [completedById], references: [id], onDelete: SetNull)\n  completedAt        DateTime?\n  grade              String? // A+, A, B+, B, C\n  completionComments String?   @db.Text\n  rejectionCount     Int       @default(0) // times rejected from EMPLOYEE_DONE\n\n  // Calendar display\n  startTime DateTime?\n  endTime   DateTime?\n  allDay    Boolean   @default(true)\n\n  // Project (tag)\n  projectId String?\n  project   TaskProject? @relation(fields: [projectId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  approvals    TaskDueDateApproval[]\n  comments     TaskComment[]\n  activityLogs TaskActivityLog[]\n  warnings     Warning[]\n  ratings      TaskRating[]\n  userTaskSeen UserTaskSeen[]\n\n  @@index([assigneeId])\n  @@index([createdById])\n  @@index([completedById])\n  @@index([status])\n  @@index([dueDate])\n  @@index([projectId])\n}\n\nmodel TaskDueDateApproval {\n  id            String             @id @default(cuid())\n  taskId        String\n  task          Task               @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  requestedById String\n  requestedBy   User               @relation(fields: [requestedById], references: [id], onDelete: Cascade)\n  oldDueDate    DateTime?\n  newDueDate    DateTime?\n  reason        String             @db.Text\n  status        TaskApprovalStatus @default(PENDING)\n  createdAt     DateTime           @default(now())\n\n  @@index([taskId])\n  @@index([requestedById])\n  @@index([status])\n}\n\nmodel UserTaskSeen {\n  id         String   @id @default(cuid())\n  userId     String\n  user       User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  taskId     String\n  task       Task     @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  lastSeenAt DateTime @default(now())\n\n  @@unique([userId, taskId])\n  @@index([userId])\n  @@index([taskId])\n}\n\nmodel TaskRating {\n  id         String   @id @default(cuid())\n  taskId     String\n  task       Task     @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  ratedById  String\n  ratedBy    User     @relation(\"TaskRatingsGiven\", fields: [ratedById], references: [id], onDelete: Cascade)\n  employeeId String\n  employee   User     @relation(\"TaskRatingsReceived\", fields: [employeeId], references: [id], onDelete: Cascade)\n  grade      Int // 1-5\n  comments   String?  @db.Text\n  action     String // \"APPROVED\" or \"REJECTED\"\n  month      Int // YYYYMM format, e.g. 202603\n  createdAt  DateTime @default(now())\n\n  @@index([employeeId, month])\n  @@index([taskId])\n}\n\nmodel TaskProject {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  createdById String\n  createdBy   User     @relation(\"TaskProjectCreator\", fields: [createdById], references: [id], onDelete: Cascade)\n  tasks       Task[]\n  createdAt   DateTime @default(now())\n\n  @@index([createdById])\n}\n\nmodel TaskComment {\n  id        String        @id @default(cuid())\n  taskId    String\n  task      Task          @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  userId    String\n  user      User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  content   String        @db.Text\n  parentId  String?\n  parent    TaskComment?  @relation(\"CommentReplies\", fields: [parentId], references: [id], onDelete: Cascade)\n  replies   TaskComment[] @relation(\"CommentReplies\")\n  createdAt DateTime      @default(now())\n\n  @@index([taskId])\n  @@index([userId])\n  @@index([parentId])\n}\n\nmodel TaskActivityLog {\n  id        String   @id @default(cuid())\n  taskId    String\n  task      Task     @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  action    String\n  details   String?  @db.Text\n  createdAt DateTime @default(now())\n\n  @@index([taskId])\n  @@index([userId])\n}\n\nmodel Warning {\n  id         String      @id @default(cuid())\n  employeeId String\n  employee   User        @relation(\"EmployeeWarnings\", fields: [employeeId], references: [id], onDelete: Cascade)\n  taskId     String?\n  task       Task?       @relation(fields: [taskId], references: [id], onDelete: SetNull)\n  type       WarningType\n  note       String      @db.Text\n  issuedById String\n  issuedBy   User        @relation(\"IssuedWarnings\", fields: [issuedById], references: [id], onDelete: Cascade)\n  createdAt  DateTime    @default(now())\n\n  @@index([employeeId])\n  @@index([taskId])\n  @@index([issuedById])\n}\n\n// MD (admin) task teams: saved sets of employees for quick task assignment\nmodel MDTaskTeam {\n  id        String             @id @default(cuid())\n  name      String\n  ownerId   String\n  owner     User               @relation(\"MDTaskTeamOwner\", fields: [ownerId], references: [id], onDelete: Cascade)\n  members   MDTaskTeamMember[]\n  createdAt DateTime           @default(now())\n  updatedAt DateTime           @updatedAt\n\n  @@index([ownerId])\n}\n\nmodel MDTaskTeamMember {\n  id         String     @id @default(cuid())\n  teamId     String\n  team       MDTaskTeam @relation(fields: [teamId], references: [id], onDelete: Cascade)\n  employeeId String\n  employee   Employee   @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  createdAt  DateTime   @default(now())\n\n  @@unique([teamId, employeeId])\n  @@index([teamId])\n  @@index([employeeId])\n}\n\n// MD Watchlist: Personal list of employees to monitor\nmodel MDWatchlistEmployee {\n  id         String   @id @default(cuid())\n  ownerId    String\n  owner      User     @relation(\"MDWatchlistOwner\", fields: [ownerId], references: [id], onDelete: Cascade)\n  employeeId String\n  employee   Employee @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  createdAt  DateTime @default(now())\n\n  @@unique([ownerId, employeeId])\n  @@index([ownerId])\n  @@index([employeeId])\n}\n\nmodel WorkLog {\n  id            String   @id @default(cuid())\n  employeeId    String\n  employee      User     @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  logDate       DateTime // The date of the work\n  intervalStart Int // 9, 12, or 15 (hour)\n  intervalEnd   Int // 12, 15, or 18 (hour)\n  description   String   @db.Text\n  createdAt     DateTime @default(now())\n\n  @@unique([employeeId, logDate, intervalStart])\n  @@index([employeeId])\n  @@index([logDate])\n}\n\nmodel PushSubscription {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  endpoint  String   @db.Text\n  p256dh    String\n  auth      String\n  createdAt DateTime @default(now())\n\n  @@unique([userId, endpoint])\n  @@index([userId])\n}\n\n// Observability: Cron job execution logs\nmodel CronJobLog {\n  id               String   @id @default(cuid())\n  jobName          String // \"attendance_sync\" | \"leads_sync\" | \"db_backup\" | \"log_cleanup\"\n  status           String // \"success\" | \"error\"\n  durationMs       Int\n  recordsProcessed Int?\n  message          String?\n  error            String?  @db.Text\n  createdAt        DateTime @default(now())\n\n  @@index([jobName, createdAt])\n  @@index([createdAt])\n}\n\n// CRM reference masters (BD / Insurance forms — dropdowns)\nmodel HospitalMaster {\n  id            String   @id @default(cuid())\n  name          String   @unique\n  address       String?  @db.Text\n  googleMapLink String?\n  isActive      Boolean  @default(true)\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  @@index([name])\n  @@index([isActive])\n}\n\nmodel DoctorMaster {\n  id        String   @id @default(cuid())\n  name      String   @unique\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([name])\n  @@index([isActive])\n}\n\nmodel TPAMaster {\n  id        String   @id @default(cuid())\n  name      String   @unique\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([name])\n  @@index([isActive])\n}\n\nmodel AnesthesiaMaster {\n  id        String   @id @default(cuid())\n  name      String   @unique\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([name])\n  @@index([isActive])\n}\n\n// Global app settings (key-value store)\nmodel AppSetting {\n  key       String   @id\n  value     String   @db.Text\n  updatedAt DateTime @updatedAt\n  updatedBy String?\n}\n\n// Observability: API request logs\nmodel RequestLog {\n  id         String   @id @default(cuid())\n  method     String\n  path       String\n  status     Int\n  durationMs Int\n  userId     String?\n  ip         String?\n  error      String?  @db.Text\n  createdAt  DateTime @default(now())\n\n  @@index([createdAt])\n  @@index([status, createdAt])\n  @@index([path, createdAt])\n}\n",
